+const std = @import("std");
+const llama = @import("llama.zig");
+const c = llama.c;
+
+/// Snapshot file magic number: 'ZELL'
+pub const SNAPSHOT_MAGIC: u32 = 0x5A454C4C;
+pub const SNAPSHOT_VERSION: u32 = 1;
+
+/// Snapshot header (64 bytes, fixed size for easy parsing)
+pub const SnapshotHeader = extern struct {
+    magic: u32 = SNAPSHOT_MAGIC,
+    version: u32 = SNAPSHOT_VERSION,
+    model_hash: u64, // Hash of model params for validation
+    n_tokens: u32, // Number of prompt tokens stored
+    _pad0: u32 = 0,
+    state_size: u64, // Size of KV cache state in bytes
+    created_at: i64, // Unix timestamp
+    flags: u32 = 0, // Reserved for future use
+    _pad1: [20]u8 = [_]u8{0} ** 20, // Padding to 64 bytes
+};
+
+comptime {
+    if (@sizeOf(SnapshotHeader) != 64) {
+        @compileError("SnapshotHeader must be exactly 64 bytes");
+    }
+}
+
+/// Snapshot options
+pub const SnapshotOptions = struct {
+    include_tokens: bool = true, // Store original tokens for verification
+};
+
+/// Info returned when loading a snapshot
+pub const SnapshotInfo = struct {
+    n_tokens: u32,
+    tokens: []c.llama_token,
+    state_size: u64,
+    created_at: i64,
+    model_hash: u64,
+};
+
+/// Compute a simple hash from model parameters for compatibility checking
+pub fn computeModelHash(model: *const llama.Model) u64 {
+    const info = model.getInfo();
+    var hash: u64 = 0;
+    hash ^= info.n_params;
+    hash ^= @as(u64, info.n_embd) << 16;
+    hash ^= @as(u64, info.n_layer) << 32;
+    hash ^= @as(u64, info.n_head) << 48;
+    hash ^= @as(u64, info.n_vocab) << 8;
+    return hash;
+}
+
+/// Create a snapshot from the current context state
+pub fn createSnapshot(
+    allocator: std.mem.Allocator,
+    ctx: *llama.Context,
+    model: *const llama.Model,
+    tokens: []const c.llama_token,
+    path: []const u8,
+    opts: SnapshotOptions,
+) !void {
+    // Get context state
+    const state = try ctx.getState(allocator);
+    defer allocator.free(state);
+
+    // Build header
+    const header = SnapshotHeader{
+        .model_hash = computeModelHash(model),
+        .n_tokens = @intCast(tokens.len),
+        .state_size = state.len,
+        .created_at = std.time.timestamp(),
+    };
+
+    // Open file for writing
+    const file = try std.fs.cwd().createFile(path, .{});
+    defer file.close();
+
+    // Write header
+    try file.writeAll(std.mem.asBytes(&header));
+
+    // Write tokens (if enabled)
+    if (opts.include_tokens and tokens.len > 0) {
+        try file.writeAll(std.mem.sliceAsBytes(tokens));
+    }
+
+    // Write state
+    try file.writeAll(state);
+}
+
+/// Load a snapshot and restore context state
+pub fn loadSnapshot(
+    allocator: std.mem.Allocator,
+    ctx: *llama.Context,
+    model: *const llama.Model,
+    path: []const u8,
+) !SnapshotInfo {
+    // Open file for reading
+    const file = try std.fs.cwd().openFile(path, .{});
+    defer file.close();
+
+    // Read header
+    var header: SnapshotHeader = undefined;
+    const header_bytes = try file.readAll(std.mem.asBytes(&header));
+    if (header_bytes != @sizeOf(SnapshotHeader)) {
+        return error.InvalidSnapshotFile;
+    }
+
+    // Validate magic and version
+    if (header.magic != SNAPSHOT_MAGIC) {
+        return error.InvalidSnapshotMagic;
+    }
+    if (header.version != SNAPSHOT_VERSION) {
+        return error.UnsupportedSnapshotVersion;
+    }
+
+    // Validate model compatibility
+    const current_hash = computeModelHash(model);
+    if (header.model_hash != current_hash) {
+        return error.ModelMismatch;
+    }
+
+    // Read tokens
+    const tokens = try allocator.alloc(c.llama_token, header.n_tokens);
+    errdefer allocator.free(tokens);
+
+    if (header.n_tokens > 0) {
+        const tokens_bytes = try file.readAll(std.mem.sliceAsBytes(tokens));
+        if (tokens_bytes != header.n_tokens * @sizeOf(c.llama_token)) {
+            return error.InvalidSnapshotFile;
+        }
+    }
+
+    // Read and restore state
+    const state = try allocator.alloc(u8, header.state_size);
+    defer allocator.free(state);
+
+    const state_bytes = try file.readAll(state);
+    if (state_bytes != header.state_size) {
+        return error.InvalidSnapshotFile;
+    }
+
+    try ctx.setState(state);
+
+    return SnapshotInfo{
+        .n_tokens = header.n_tokens,
+        .tokens = tokens,
+        .state_size = header.state_size,
+        .created_at = header.created_at,
+        .model_hash = header.model_hash,
+    };
+}
+
+/// Read snapshot info without loading state
+pub fn getSnapshotInfo(path: []const u8) !SnapshotHeader {
+    const file = try std.fs.cwd().openFile(path, .{});
+    defer file.close();
+
+    var header: SnapshotHeader = undefined;
+    const bytes_read = try file.readAll(std.mem.asBytes(&header));
+    if (bytes_read != @sizeOf(SnapshotHeader)) {
+        return error.InvalidSnapshotFile;
+    }
+
+    if (header.magic != SNAPSHOT_MAGIC) {
+        return error.InvalidSnapshotMagic;
+    }
+
+    return header;
+}
+
+/// Format snapshot info for display
+pub fn formatSnapshotInfo(header: SnapshotHeader, writer: anytype) !void {
+    try writer.print("Snapshot Info:\n", .{});
+    try writer.print("  Version:    {d}\n", .{header.version});
+    try writer.print("  Model Hash: 0x{x:0>16}\n", .{header.model_hash});
+    try writer.print("  Tokens:     {d}\n", .{header.n_tokens});
+    try writer.print("  State Size: {d} bytes ({d:.2} MB)\n", .{
+        header.state_size,
+        @as(f64, @floatFromInt(header.state_size)) / (1024.0 * 1024.0),
+    });
+
+    // Format timestamp
+    const ts = header.created_at;
+    if (ts > 0) {
+        try writer.print("  Created:    {d} (Unix timestamp)\n", .{ts});
+    }
+}
